DO $$
BEGIN
    RAISE NOTICE 'eval_datasets: % rows', (SELECT COUNT(*) FROM eval_datasets);
    RAISE NOTICE 'eval_test_cases: % rows', (SELECT COUNT(*) FROM eval_test_cases);
END $$;
